#!/bin/bash`n# в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—`n# в•‘        CubiVeil Unit Tests - Rollback Module              в•‘`n# в•‘        РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ lib/modules/rollback/install.sh       в•‘`n# в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ`n`nset -euo pipefail`n`n# в”Ђв”Ђ РџРѕРґРєР»СЋС‡РµРЅРёРµ С‚РµСЃС‚РѕРІС‹С… СѓС‚РёР»РёС‚ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nSCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")/.." && pwd)"`nsource "${SCRIPT_DIR}/lib/test-utils.sh"`n`n# в”Ђв”Ђ Р—Р°РіСЂСѓР·РєР° С‚РµСЃС‚РёСЂСѓРµРјРѕРіРѕ РјРѕРґСѓР»СЏ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nMODULE_PATH="${SCRIPT_DIR}/lib/modules/rollback/install.sh"`n`nif [[ ! -f "$MODULE_PATH" ]]; then`n  echo "РћС€РёР±РєР°: Rollback module РЅРµ РЅР°Р№РґРµРЅ: $MODULE_PATH"`n  exit 1`nfi`n`n# в”Ђв”Ђ Mock Р·Р°РІРёСЃРёРјРѕСЃС‚РµР№ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`nlog_step() { echo "[LOG_STEP] $1: $2" >&2; }`nlog_debug() { echo "[DEBUG] $1" >&2; }`nlog_success() { echo "[SUCCESS] $1" >&2; }`nlog_warn() { echo "[WARN] $1" >&2; }`nlog_info() { echo "[INFO] $1" >&2; }`nlog_error() { echo "[ERROR] $1" >&2; }`n`n# Mock core С„СѓРЅРєС†РёР№`ndir_ensure() { mkdir -p "$1" 2>/dev/null || true; }`n`nsvc_active() { return 1; }`nsvc_stop() {`n  echo "[MOCK] svc_stop: $1" >&2`n  return 0`n}`nsvc_start() {`n  echo "[MOCK] svc_start: $1" >&2`n  return 0`n}`n`n# Mock РґР»СЏ РїСЂРѕРІРµСЂРєРё SHA256`nverify_sha256() {`n  # shellcheck disable=SC2034`n  local file="$1"`n  # shellcheck disable=SC2034`n  local expected="$2"`n  # Р”Р»СЏ С‚РµСЃС‚РѕРІ РІСЃРµРіРґР° РІРѕР·РІСЂР°С‰Р°РµРј true`n  return 0`n}`n`n# Mock РґР»СЏ РїСЂРѕРІРµСЂРєРё SSL`nverify_ssl_cert() { return 0; }`n`n# Mock РґР»СЏ openssl`nopenssl() {`n  if [[ "$*" == *"-subject"* ]]; then`n    echo "subject=CN = test.example.com"`n  else`n    echo "[MOCK] openssl: $*" >&2`n  fi`n}`n`n# в”Ђв”Ђ Р—Р°РіСЂСѓР·РєР° РјРѕРґСѓР»СЏ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`n# shellcheck source=lib/modules/rollback/install.sh`nsource "$MODULE_PATH"`n`n# в”Ђв”Ђ РўРµСЃС‚: С„Р°Р№Р» СЃСѓС‰РµСЃС‚РІСѓРµС‚ в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_file_exists() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ РЅР°Р»РёС‡РёСЏ С„Р°Р№Р»Р° РјРѕРґСѓР»СЏ..."`n`n  if [[ -f "$MODULE_PATH" ]]; then`n    pass "Rollback module: С„Р°Р№Р» СЃСѓС‰РµСЃС‚РІСѓРµС‚"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "Rollback module: С„Р°Р№Р» РЅРµ РЅР°Р№РґРµРЅ"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: СЃРёРЅС‚Р°РєСЃРёСЃ СЃРєСЂРёРїС‚Р° в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_syntax() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ СЃРёРЅС‚Р°РєСЃРёСЃР°..."`n`n  if bash -n "$MODULE_PATH" 2>/dev/null; then`n    pass "Rollback module: СЃРёРЅС‚Р°РєСЃРёСЃ РєРѕСЂСЂРµРєС‚РµРЅ"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "Rollback module: СЃРёРЅС‚Р°РєСЃРёС‡РµСЃРєР°СЏ РѕС€РёР±РєР°"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: shebang в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_shebang() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ shebang..."`n`n  local shebang`n  shebang=$(head -1 "$MODULE_PATH")`n`n  if [[ "$shebang" == "#!/bin/bash" ]]; then`n    pass "Rollback module: РєРѕСЂСЂРµРєС‚РЅС‹Р№ shebang"`n    ((TESTS_PASSED++)) || true`n  else`n    fail "Rollback module: РЅРµРєРѕСЂСЂРµРєС‚РЅС‹Р№ shebang: $shebang"`n  fi`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: rollback_init в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_rollback_init() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ rollback_init..."`n`n  local test_backup_dir="/tmp/test-rollback-$$"`n  BACKUP_DIR="$test_backup_dir"`n  ROLLBACK_TEMP_DIR="${test_backup_dir}/temp"`n`n  rollback_init`n`n  pass "rollback_init: РІС‹Р·РІР°РЅР° Р±РµР· РѕС€РёР±РѕРє"`n  ((TESTS_PASSED++)) || true`n`n  rm -rf "$test_backup_dir"`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: rollback_list_backups в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_rollback_list_backups() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ rollback_list_backups..."`n`n  local test_backup_dir="/tmp/test-rollback-$$"`n  local test_archive_dir="${test_backup_dir}/archives"`n  mkdir -p "$test_archive_dir"`n`n  BACKUP_DIR="$test_backup_dir"`n  BACKUP_ARCHIVE_DIR="$test_archive_dir"`n`n  # РЎРѕР·РґР°С‘Рј С‚РµСЃС‚РѕРІС‹Р№ Р±СЌРєР°Рї`n  echo "test" >"${test_archive_dir}/test-backup.tar.gz"`n`n  rollback_list_backups || true`n`n  pass "rollback_list_backups: РІС‹Р·РІР°РЅР° Р±РµР· РѕС€РёР±РѕРє"`n  ((TESTS_PASSED++)) || true`n`n  rm -rf "$test_backup_dir"`n}`n`n# в”Ђв”Ђ РўРµСЃС‚: rollback_select_backup в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ`ntest_rollback_select_backup_mock() {`n  info "РўРµСЃС‚РёСЂРѕРІР°РЅРёРµ rollback_select_backup (mock)..."`n`n  local test_backup_dir="/tmp/test-rollback-$$"`n  local test_archive_dir="${test_backup_dir}/archives"`n  mkdir -p "$test_archive_dir"`n`n  BACKUP_DIR="$test_backup_dir"`n  BACKUP_ARCHIVE_DIR="$test_archive_dir"`n`n  # РЎРѕР·РґР°С‘Рј С‚РµСЃС‚РѕРІС‹Р№ Р±СЌРєР°Рї`n  echo "test" >"${test_archive_dir}/test-backup.tar.gz"`n`n  # Mock РґР»СЏ read`n  read() {`n    selection="1" # Р’РѕР·РІСЂР°С‰Р°РµРј РїРµСЂРІС‹Р№ РІР°СЂРёР°РЅС‚`n    return 0`n  }`n`n  # Р¤СѓРЅРєС†РёСЏ РјРѕР¶РµС‚ РІС‹Р№С‚Рё РёР·-Р·Р° exit 